"use client";

/**
 * /alerts/daily — Daily Research Alerts Page
 *
 * Displays research alerts generated by DailyAlertEngine.
 * All alerts are informational. None constitute investment instructions.
 */

import React, { useState } from 'react';
import { useApiData } from '@/hooks/useApiData';
import { GlassCard } from '@/components/ui/glass-card';
import { LoadingSpinner } from '@/components/ui/loading';
import { Disclaimer } from '@/components/ui/disclaimer';
import { AlertSeverityBadge } from '@/components/ui/badges';
import { LimitationBlock } from '@/components/ui/limitation-block';
import {
  Bell, AlertTriangle, Info, TrendingUp, TrendingDown,
  Shield, Database, RefreshCw, ChevronDown, ChevronUp, Minus
} from 'lucide-react';

// ─── Types ───────────────────────────────────────────────────────

type AlertType =
  | 'market_regime_changed' | 'candidate_upgraded' | 'candidate_downgraded'
  | 'alpha_improved' | 'alpha_dropped' | 'watchlist_risk_escalated'
  | 'newly_insufficient_data' | 'data_quality_warning' | 'comparison_unavailable';

type AlertSeverity = 'info' | 'caution' | 'warning';

interface DailyAlert {
  type: AlertType;
  severity: AlertSeverity;
  title: string;
  message: string;
  symbol?: string;
  name?: string;
  previousValue?: string;
  currentValue?: string;
  metadata?: Record<string, unknown>;
}

interface DailyAlertResult {
  reportDate: string;
  summary: string;
  overallSeverity: AlertSeverity;
  alerts: DailyAlert[];
  comparisonAvailable: boolean;
  previousSnapshotDate: string | null;
  limitations: string[];
  generatedAt: string;
}

// ─── Styles ──────────────────────────────────────────────────────

const SEVERITY_STYLE: Record<AlertSeverity, { bg: string; text: string; border: string; icon: React.ReactNode; label: string }> = {
  warning: {
    bg: 'bg-red-50 dark:bg-red-950/20',
    text: 'text-red-700 dark:text-red-400',
    border: 'border-red-200 dark:border-red-800/40',
    icon: <AlertTriangle className="h-4 w-4" />,
    label: '注意',
  },
  caution: {
    bg: 'bg-amber-50 dark:bg-amber-950/20',
    text: 'text-amber-700 dark:text-amber-400',
    border: 'border-amber-200 dark:border-amber-800/40',
    icon: <AlertTriangle className="h-4 w-4" />,
    label: '提醒',
  },
  info: {
    bg: 'bg-blue-50 dark:bg-blue-950/20',
    text: 'text-blue-700 dark:text-blue-400',
    border: 'border-blue-200 dark:border-blue-800/40',
    icon: <Info className="h-4 w-4" />,
    label: '資訊',
  },
};

const TYPE_STYLE: Record<AlertType, { label: string; icon: React.ReactNode }> = {
  market_regime_changed:    { label: '市場轉換',   icon: <TrendingUp className="h-3 w-3" /> },
  candidate_upgraded:       { label: '候選升級',   icon: <TrendingUp className="h-3 w-3" /> },
  candidate_downgraded:     { label: '候選降級',   icon: <TrendingDown className="h-3 w-3" /> },
  alpha_improved:           { label: 'Alpha 改善', icon: <TrendingUp className="h-3 w-3" /> },
  alpha_dropped:            { label: 'Alpha 下滑', icon: <TrendingDown className="h-3 w-3" /> },
  watchlist_risk_escalated: { label: '風險升高',   icon: <Shield className="h-3 w-3" /> },
  newly_insufficient_data:  { label: '資料不足',   icon: <Database className="h-3 w-3" /> },
  data_quality_warning:     { label: '資料品質',   icon: <Database className="h-3 w-3" /> },
  comparison_unavailable:   { label: '比較不可用', icon: <Minus className="h-3 w-3" /> },
};

// ─── Page ────────────────────────────────────────────────────────

export default function AlertsPage() {
  const { data, loading, error, refetch } = useApiData<DailyAlertResult>('/api/notify/daily');
  const [severityFilter, setSeverityFilter] = useState<'all' | AlertSeverity>('all');
  const [typeFilter, setTypeFilter] = useState<string>('all');

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8 flex items-center justify-center min-h-[400px]">
        <LoadingSpinner />
        <span className="ml-3 text-muted-foreground">產生每日提醒...</span>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="container mx-auto px-4 py-8">
        <GlassCard className="p-8 text-center">
          <AlertTriangle className="h-10 w-10 mx-auto mb-3 text-amber-500" />
          <p className="text-muted-foreground mb-4">{error ?? '無法取得提醒資料'}</p>
          <button onClick={refetch} className="px-4 py-2 rounded-lg bg-primary/10 text-primary hover:bg-primary/20 text-sm transition-colors">重試</button>
        </GlassCard>
      </div>
    );
  }

  const filtered = data.alerts.filter(a => {
    if (severityFilter !== 'all' && a.severity !== severityFilter) return false;
    if (typeFilter !== 'all' && a.type !== typeFilter) return false;
    return true;
  });

  const warningCount = data.alerts.filter(a => a.severity === 'warning').length;
  const cautionCount = data.alerts.filter(a => a.severity === 'caution').length;
  const infoCount = data.alerts.filter(a => a.severity === 'info').length;

  return (
    <div className="container mx-auto px-4 py-8 space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Bell className="h-6 w-6 text-primary" />
            每日研究提醒
          </h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            {data.reportDate} · 研究層提醒，非投資指令
          </p>
        </div>
        <button onClick={refetch} className="self-start px-3 py-1.5 rounded-lg text-sm bg-primary/10 text-primary hover:bg-primary/20 transition-colors flex items-center gap-1">
          <RefreshCw className="h-3.5 w-3.5" />更新
        </button>
      </div>

      {/* Summary card */}
      <GlassCard className="p-5">
        <div className="flex flex-col sm:flex-row sm:items-start gap-4">
          <AlertSeverityBadge severity={data.overallSeverity} />
          <p className="text-sm leading-relaxed">{data.summary}</p>
        </div>

        {/* Count row */}
        <div className="mt-4 flex flex-wrap gap-3">
          {[
            { label: '警告', count: warningCount, color: 'text-red-600 dark:text-red-400', sev: 'warning' as AlertSeverity },
            { label: '提醒', count: cautionCount, color: 'text-amber-600 dark:text-amber-400', sev: 'caution' as AlertSeverity },
            { label: '資訊', count: infoCount,    color: 'text-blue-600 dark:text-blue-400', sev: 'info' as AlertSeverity },
          ].map(({ label, count, color, sev }) => (
            <button key={sev}
              onClick={() => setSeverityFilter(severityFilter === sev ? 'all' : sev)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm transition-colors ${
                severityFilter === sev ? 'bg-muted' : 'bg-muted/30 hover:bg-muted/50'
              }`}>
              <span className={`font-bold ${color}`}>{count}</span>
              <span className="text-muted-foreground">{label}</span>
            </button>
          ))}
        </div>

        {/* Comparison availability */}
        {!data.comparisonAvailable && (
          <div className="mt-3 flex items-start gap-2 text-xs text-muted-foreground">
            <Info className="h-3.5 w-3.5 mt-0.5 shrink-0" />
            尚無前日快照，升降級提醒不可用。請至每日報告頁建立快照以啟用歷史比較。
          </div>
        )}
        {data.comparisonAvailable && (
          <div className="mt-3 text-xs text-green-600 dark:text-green-400">
            ✓ 與 {data.previousSnapshotDate} 快照比較中
          </div>
        )}
      </GlassCard>

      {/* Type filter */}
      {data.alerts.length > 0 && (
        <div className="flex flex-wrap gap-1.5">
          <button onClick={() => setTypeFilter('all')}
            className={`px-2.5 py-1 rounded text-xs transition-colors ${typeFilter === 'all' ? 'bg-primary text-primary-foreground' : 'bg-muted/30 hover:bg-muted/50'}`}>
            全部 ({data.alerts.length})
          </button>
          {(Object.keys(TYPE_STYLE) as AlertType[]).map(t => {
            const count = data.alerts.filter(a => a.type === t).length;
            if (count === 0) return null;
            return (
              <button key={t} onClick={() => setTypeFilter(typeFilter === t ? 'all' : t)}
                className={`px-2.5 py-1 rounded text-xs transition-colors ${typeFilter === t ? 'bg-primary text-primary-foreground' : 'bg-muted/30 hover:bg-muted/50'}`}>
                {TYPE_STYLE[t].label} ({count})
              </button>
            );
          })}
        </div>
      )}

      {/* Alert list */}
      {filtered.length === 0 ? (
        <GlassCard className="p-10 text-center text-muted-foreground">
          <Bell className="h-10 w-10 mx-auto mb-3 opacity-30" />
          <p>{data.alerts.length === 0 ? '今日無研究提醒' : '無符合篩選條件的提醒'}</p>
        </GlassCard>
      ) : (
        <div className="space-y-3">
          {filtered.map((alert, i) => (
            <AlertCard key={`${alert.type}-${alert.symbol ?? i}`} alert={alert} />
          ))}
        </div>
      )}

      {/* Limitations */}
      <LimitationBlock items={data.limitations} />

      <Disclaimer
        warning="本提醒為系統自動產生之研究摘要，不構成投資建議。所有提醒基於模型推估，不保證未來表現。"
        source="DailyAlertEngine: DailySnapshotEngine + StrategyScreenEngine + MarketRegimeEngine"
        methodology="規則式比較引擎：比較前日快照與當日分析結果，無 AI 黑盒預測"
        variant="detailed"
      />

      <p className="text-xs text-muted-foreground text-center">
        產生時間: {new Date(data.generatedAt).toLocaleString('zh-TW')}
      </p>
    </div>
  );
}

// ─── Alert Card ──────────────────────────────────────────────────

function AlertCard({ alert: a }: { alert: DailyAlert }) {
  const [expanded, setExpanded] = useState(false);
  const sev = SEVERITY_STYLE[a.severity];
  const type = TYPE_STYLE[a.type];

  return (
    <div className={`rounded-xl border p-4 ${sev.bg} ${sev.border}`}>
      <div className="flex items-start justify-between gap-3">
        <div className="flex items-start gap-3 flex-1 min-w-0">
          {/* Severity icon */}
          <span className={`mt-0.5 shrink-0 ${sev.text}`}>{sev.icon}</span>

          <div className="flex-1 min-w-0">
            {/* Badges */}
            <div className="flex flex-wrap gap-1.5 mb-1.5">
              <span className={`text-[10px] px-1.5 py-0.5 rounded font-medium ${sev.bg} ${sev.text} border ${sev.border}`}>
                {sev.label}
              </span>
              <span className="text-[10px] px-1.5 py-0.5 rounded font-medium bg-muted/50 text-muted-foreground flex items-center gap-0.5">
                {type.icon}{type.label}
              </span>
              {a.symbol && (
                <span className="text-[10px] px-1.5 py-0.5 rounded font-medium bg-primary/5 text-primary font-mono">
                  {a.symbol}
                </span>
              )}
            </div>

            {/* Title */}
            <p className={`text-sm font-medium ${sev.text}`}>{a.title}</p>

            {/* Message */}
            <p className="text-xs text-muted-foreground mt-1 leading-relaxed">{a.message}</p>

            {/* Before/after */}
            {a.previousValue && a.currentValue && (
              <div className="flex items-center gap-2 mt-2 text-xs">
                <span className="px-2 py-0.5 rounded bg-muted/40 text-muted-foreground">{a.previousValue}</span>
                <span className="text-muted-foreground">→</span>
                <span className={`px-2 py-0.5 rounded ${sev.bg} ${sev.text}`}>{a.currentValue}</span>
              </div>
            )}

            {/* Metadata (expandable) */}
            {a.metadata && Object.keys(a.metadata).length > 0 && (
              <button onClick={() => setExpanded(!expanded)}
                className="mt-2 flex items-center gap-1 text-[11px] text-muted-foreground hover:text-foreground transition-colors">
                {expanded ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />}
                {expanded ? '收起' : '詳細資訊'}
              </button>
            )}
            {expanded && a.metadata && (
              <div className="mt-2 p-2 rounded bg-muted/20 text-xs text-muted-foreground space-y-0.5">
                {Object.entries(a.metadata).map(([k, v]) => (
                  <div key={k}><span className="font-medium">{k}:</span> {String(v)}</div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
